/// Replay one patch against a per-line generation vector.
pub fn apply_patch_to_blame(blame: &[i64], patch: &str, gen: i64) -> Vec<i64> {
    let hunks = parse_hunks(patch);
    if hunks.is_empty() {
        return blame.to_vec();
    }

    let mut result = Vec::new();
    let mut old_idx: usize = 0;

    for hunk in &hunks {
        let hunk_start = hunk.old_start.saturating_sub(1);
        while old_idx < hunk_start && old_idx < blame.len() {
            result.push(blame[old_idx]);
            old_idx += 1;
        }

        for line in &hunk.lines {
            match line.kind {
                HunkKind::Context => {
                    if old_idx < blame.len() {
